};

/**
 * PopUp창에서 사용되는 각 Cd,Nm에 대해서 POPUP표시 및 해당 값이 없을경우는 코드와 이름을 초기화 시킨다.
 * flag값이 CD:코드변경이 없으면 POPUP안뛰움, NM:무조건 POPUP뛰움
 * TOBE 사용안함(UDC 사용)
 */
scwin.f_CheckPopUp = function (orgObjCd, orgObjNm, select_code, flag) {
    if (flag == "CD") {
        if (orgObjCd.getValue() == orgObjCd.hidVal) {
            return;
        } else {
            orgObjNm.setValue("");
        }
    } else {
        if (orgObjNm.getValue() == orgObjNm.hidVal) {
            return;
        } else {
            orgObjCd.setValue("");
        }
    }
    if (orgObjCd.getValue().trim() != "" || flag == "NM") {
        if (orgObjNm.getValue().trim() != "" || flag == "CD") {
            orgObjCd.setValue(orgObjCd.getValue().trim());
            orgObjNm.setValue(orgObjNm.getValue().trim());
            scwin.f_openPopUp(orgObjCd, orgObjNm, select_code, "NO");
        }
    } else {
        orgObjNm.setValue("");
        orgObjCd.setValue("");
        orgObjCd.hidVal = "";
    }
};

/**
 * 팝업결과
 * TOBE 사용안함(UDC 사용)
 */
scwin.f_resultPopUp = function (orgObjCd, orgObjNm, rtnList) {
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        orgObjCd.Text = rtnList[0]; // 코드값
        orgObjNm.Text = rtnList[1]; // 코드명
        orgObjCd.hidVal = rtnList[0]; // HIDDEN 코드값
        orgObjNm.hidVal = rtnList[1]; // HIDDEN 코드명
    } else {
        orgObjCd.Text = "";
        orgObjNm.Text = "";
        orgObjCd.hidVal = "";
        orgObjNm.hidVal = "";
    }
};

/**
 * 그리드 팝업호출
 */
scwin.f_GridPop = async function(colId, row, data, close) {
    scwin.f_commCdPopupRow = row;
    let sqlId = "";
    if (colId == "distGiveAcctDeptCd") {
        ds_giveDept.setCellData(row, "distGiveAcctDeptCd", "");
        ds_giveDept.setCellData(row, "acctDeptNm"        , "");
        let param = ica_fromDate.getValue()+"01"+",,,0,givedept,1,,,,"+ ed_coCd.getValue();
        udc_comCode_Grid.setSelectId("retrieveAcctDeptCdInfo");
        //조회조건 9번째, 전체검색허용여부 15번째
        await udc_comCode_Grid.cfCommonPopUp(
            scwin.udc_comCode_Grid_distGiveAcctDeptCd_callBackFunc
            , data
            , ""
            , close
            , null
            , null
            , null
            , null
            , param
            , null
            , null
            , null
            , null
            , null
            , "F"
            , null);
    }
};

/**
 * 배부부서코드(그리드팝업)
 */
scwin.udc_comCode_Grid_distGiveAcctDeptCd_callBackFunc = function(ret) {
    // let rowIdx = gr_giveDept.getFocusedRowIndex();
    let rowIdx = scwin.f_commCdPopupRow;
    if (ret[0] != "N/A" && !$c.gus.cfIsNull(ret)) {
        ds_giveDept.setCellData(rowIdx, "distGiveAcctDeptCd", ret[0]); //배부부서코드
        ds_giveDept.setCellData(rowIdx, "acctDeptNm"        , ret[1]); //배부부서명
    }else {
        ds_giveDept.setCellData(rowIdx, "distGiveAcctDeptCd", "");     //배부부서코드
        ds_giveDept.setCellData(rowIdx, "acctDeptNm"        , "");     //배부부서명
    }
};


/**
* 조회버튼
*/
scwin.f_Retrieve = async function() {
    // 조회 필수조건 확인
    let ret = await $c.gus.cfValidate([ica_fromDate, ed_coCd]);
    if (!ret) {
        return false;
    }
    let date = ica_fromDate.getValue().trim();
    //계획일경우는 년도+"00", 실적일경우는 년월
    // 계획일경우
    if (rd_distClsCd.getValue() == "1") {
        if(ica_fromDate.getValue().length != 4){
            await $c.gus.cfAlertMsg("배부년도은(는) 4자리수만큼 입력하십시오.");
            ica_fromDate.focus();
            return;
        }
        dma_search.set("distYm", ica_fromDate.getValue().trim() + "00");
        date = ica_fromDate.getValue()+"0101";

    // 실적배부일경우
    } else {
        if(ica_fromDate.getValue().length != 6){
            await $c.gus.cfAlertMsg("배부년월은(는) 6자리수만큼 입력하십시오.");
            ica_fromDate.focus();
            return;
        }
        dma_search.set("distYm", ica_fromDate.getValue().trim());
        date = ica_fromDate.getValue()+"01";
    }

    ret = await $c.date.isDate(date);
    if(!ret) {
        await $c.gus.cfAlertMsg("올바른 배부년월을(를) 입력하십시오.");
        ica_fromDate.focus();
        return;
    }

    scwin.setInit();
    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    gr_giveDept.setNoResultMessageVisible(true);
    gr_recvDept.setNoResultMessageVisible(true);
    gr_acntDept.setNoResultMessageVisible(true);
    let rowCnt1 = ds_giveDept.getRowCount();
    let rowCnt2 = ds_recvDept.getRowCount();
    let rowCnt3 = ds_acntDept.getRowCount();
    totalRows1.setValue(rowCnt1)   
    totalRows2.setValue(rowCnt2)   
    totalRows3.setValue(rowCnt3)   
    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        // ds_giveDept.sort("distGiveAcctDeptCd", 0);
        gr_giveDept.setFocusedCell(0, 0);
        gr_recvDept.setFocusedCell(0, 0);
        gr_acntDept.setFocusedCell(0, 0);
    }
};

// scwin.sbm_retrieve_submiterror = function (e) {
//     $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
// };


/**
 * 저장
 */
scwin.f_Save = async function () {
    if (ds_recvDept.getModifiedIndex().length < 1) {
        // await $c.win.alert("변경된 사항이 없습니다.");
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["배부받는 부서"]);
        return;
    }
    if (await $c.win.confirm(MSG_CM_CRM_001)) {
	    sbm_save.userData1="noError";
        $c.sbm.execute(sbm_save);
    }
};

scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        await $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
        return;
    }
    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);        
        scwin.f_Retrieve(); 
    }
};

// scwin.sbm_save_submiterror = function (e) {
//     $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
// };


/**
 * 우측으로이동 버튼 클릭시 Row Delete (mark)
 */
scwin.f_LeftMove = function() {

    let selectedIndex = gr_recvDept.getAllFocusedRowIndex();

    if (!selectedIndex || selectedIndex.length === 0) {
        return;
    }

    for (let i = selectedIndex.length - 1; i >= 0; i--) {

        let row = selectedIndex[i];

        if (ds_recvDept.getRowStatus(row) == "C") {
            ds_recvDept.removeRow(row);
        } else {
            ds_recvDept.deleteRow(row);
        }
    }

    if (ds_recvDept.getRowCount() > 0) {
        gr_recvDept.setFocusedCell(0, 0);
    }
};


/**
 * 좌측으로 이동(전체부서 => 배부받는부서)
 */
scwin.f_RightMove = async function () {
    // for (let i=0; i<ds_acntDept.getRowCount(); i++) {
    //     // if ((type == 'a') || ((type == 'm') && (ds_acntDept.RowMark(i) == 1))) {
    //         if (ds_recvDept.getMatchedIndex("distRecvAcctDeptCd", ds_acntDept.getCellData(i, "acctDeptCd")).lnegth > 0) {
    //             await $c.win.alert("부서코드 " + ds_acntDept.getCellData(i, "acctDeptCd") + "는 이미 추가된 행입니다.");
    //             return;
    //         }

    //         if (ds_giveDept.getCellData(ds_giveDept.getRowPosition(), "distGiveAcctDeptCd") == ds_acntDept.getCellData(i, "acctDeptCd") ) {
    //             await $c.win.alert("배부부서코드와 중복될 수 없습니다. ");
    //             return;
    //         }
    //         let row    = ds_recvDept.insertRow();
    //         let distYm = "";
    //         // 계획일경우는 년도+"00", 실적일경우는 년월
    //         if (rd_distClsCd.getValue() == "1") {
    //             distYm = ica_fromDate.getValue().trim() + "00";
    //         } else {
    //             distYm = ica_fromDate.getValue().trim();
    //         }
    //         ds_recvDept.setCellData(row, "distYm"              , distYm);
    //         ds_recvDept.setCellData(row, "distDegCd"           , lc_degCd.getValue());
    //         ds_recvDept.setCellData(row, "distGiveAcctDeptCd"  , ds_giveDept.getCellData(ds_giveDept.getRowPosition(), "distGiveAcctDeptCd"));
    //         ds_recvDept.setCellData(row, "distRecvAcctDeptCd"  , ds_acntDept.getCellData(i, "acctDeptCd"));
    //         ds_recvDept.setCellData(row, "acctDeptNm"          , ds_acntDept.getCellData(i, "acctDeptNm"));
    //     // }
    // }

    //tobe 수정 로직

    let selectRows = gr_acntDept.getAllFocusedRowIndex();

    if (!selectRows || selectRows.length === 0) {
        await $c.win.alert("선택된 전사 부서코드가 없습니다.");
        return;
    }

    for (let i = 0; i < selectRows.length; i++) {

        let selectRow = selectRows[i];

        let distRecvAcctDeptCdArry = ds_recvDept.getMatchedIndex(
            "distRecvAcctDeptCd",
            ds_acntDept.getCellData(selectRow, "acctDeptCd")
        );

        if (distRecvAcctDeptCdArry.length > 0) {
            await $c.win.alert(
                "부서코드 " + ds_acntDept.getCellData(selectRow, "acctDeptCd") + "는 이미 추가된 행입니다."
            );
            break;
        }

        if (
            ds_giveDept.getCellData(ds_giveDept.getRowPosition(), "distGiveAcctDeptCd") ==
            ds_acntDept.getCellData(selectRow, "acctDeptCd")
        ) {
            await $c.win.alert("배부부서코드와 중복될 수 없습니다.");
            break; 
        }

        let row = ds_recvDept.insertRow();
        let distYm = "";

        if (rd_distClsCd.getValue() == "1") {
            distYm = ica_fromDate.getValue().trim() + "00";
        } else {
            distYm = ica_fromDate.getValue().trim();
        }

        ds_recvDept.setCellData(row, "distYm", distYm);
        ds_recvDept.setCellData(row, "distDegCd", lc_degCd.getValue());
        ds_recvDept.setCellData(
            row,
            "distGiveAcctDeptCd",
            ds_giveDept.getCellData(ds_giveDept.getRowPosition(), "distGiveAcctDeptCd")
        );
        ds_recvDept.setCellData(
            row,
            "distRecvAcctDeptCd",
            ds_acntDept.getCellData(selectRow, "acctDeptCd")
        );
        ds_recvDept.setCellData(
            row,
            "acctDeptNm",
            ds_acntDept.getCellData(selectRow, "acctDeptNm")
        );

        gr_recvDept.setFocusedCell(row, 0);
    }
};


/**
 * 첫번째  그리드추가 - 차수별,배부부서코드  적용
 */
scwin.f_AddRowRegion = async function () {
//    gr_giveDept.setEventPause("", true);
    let row = ds_giveDept.insertRow();
    ds_giveDept.setCellData(row    , "distDegCd", lc_degCd.getValue());
    // 계획일경우
    if (rd_distClsCd.getValue() == "1") {
        ds_giveDept.setCellData(row, "distYM", ica_fromDate.getValue().trim()+"00");
    // 실적배부일경우
    }else {
        ds_giveDept.setCellData(row, "distYM", ica_fromDate.getValue().trim());
    }
    gr_giveDept.setFocusedCell(row , "distGiveAcctDeptCd", true);
//    gr_giveDept.setEventPause("", false);
};


/**
 * 행삭제
 */
scwin.f_DeleteRow = function() {
    let row = ds_giveDept.getRowPosition();
    //배부받는 부서 insert 삭제처리
    let insertRow = ds_recvDept.getInsertedIndex();
    for(let i=insertRow.length-1; i>=0; i--) {
        ds_recvDept.removeRow(insertRow[i]);
    }

    if(ds_giveDept.getRowStatus(row) == "C") {
        ds_giveDept.removeRow(row);

    }else {
        ds_giveDept.deleteRow(row);
        gr_giveDept.setCellReadOnly(row, "distGiveAcctDeptCd", true);
        gr_giveDept.setFocusedCell(row, 0);
        //배부받는 있는것 삭제처리(기존 배부부서 있는 경우만)
        for (let i=0; i<ds_recvDept.getRowCount(); i++) {
            ds_recvDept.deleteRow(i);
        }
    }
};


/**
 * 행취소
 */
scwin.f_Cancel = function() {
    let row = ds_giveDept.getRowPosition();
    if(ds_giveDept.getRowStatus(row) == "C") {
        ds_giveDept.removeRow(row);
    }else {
        ds_giveDept.undoRow(row);
        ds_recvDept.undoAll();
        let insertRow = ds_recvDept.getInsertedIndex();
        for(let i=insertRow.length-1; i>=0; i--) {
            ds_recvDept.removeRow(insertRow[i]);
        }
    }
    gr_giveDept.setFocusedCell(row, 0);
};


